-- =====================================================================
-- 면적매트릭스 좌표 siz 등록 + 면적 component_prices 마이그레이션 (migrate.sql)
-- 생성: gen_migrate_sql.py (입력 CSV verbatim, 손편집 금지)
-- 단일 트랜잭션. 로더(apply.sh)가 ROLLBACK 주입(기본 DRY-RUN), --commit=인간 승인.
-- 면적 13(실사11+현수막2) + 아크릴은 이미 PRF_POSTER_FIXED 바인딩 — 재바인딩 없음(가드로 확인).
-- =====================================================================
\set ON_ERROR_STOP on
\timing on
BEGIN;

-- 가드 0: 면적 13(실사11+현수막2) + 아크릴 3소재가 PRF_POSTER_FIXED에 바인딩되어 있는지 확인.
--          (재바인딩하지 않음 — 이미 GO 커밋. 좌표 siz + 면적 단가만 추가.)
DO $$
DECLARE n int;
BEGIN
  SELECT count(*) INTO n FROM t_prd_product_price_formulas
   WHERE prd_cd IN ('PRD_000118','PRD_000119','PRD_000120','PRD_000121','PRD_000122','PRD_000123',
                    'PRD_000124','PRD_000125','PRD_000126','PRD_000127','PRD_000128','PRD_000138','PRD_000139')
     AND frm_cd='PRF_POSTER_FIXED';
  IF n < 13 THEN
    RAISE WARNING '면적 13 PRF_POSTER_FIXED 바인딩이 13 미만 (실제 %). 재바인딩은 하지 않음 — 확인만.', n;
  END IF;
END $$;

\i 01_siz_register.sql
\i 02_component_prices.sql

